import { useState } from "react";
import "./App.css";
import Navbar from "./Components/Navbar";
import About from "./Components/About";
import Projects from "./Components/Projects";
import Stack from "./Components/Stack";
import Contact from "./Components/Contact";
import Footer from "./Components/Footer";
import Hero from "./Components/Hero";
import { motion } from "framer-motion";

function SectionWrapper({ children }) {
  return (
    <div className="relative z-10">
      {children}
    </div>
  );
}

function App() {
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.6 }}
      className="relative min-h-screen text-white font-sans overflow-x-hidden "
    >
      <motion.div
        className="absolute top-1/3 left-1/2 -translate-x-1/2 w-[1000px] h-[1000px] bg-red-600/20 rounded-full blur-[220px]"
        animate={{
          opacity: [0.15, 0.25, 0.15],
          scale: [1, 1.1, 1],
        }}
        transition={{
          duration: 18,
          repeat: Infinity,
          ease: "easeInOut",
        }}
      />

      {/* ===== FONDO ANIMADO ===== */}
      <div className="fixed inset-0 -z-10 overflow-hidden">

        {/* Blob 1 */}
        <motion.div
          className="absolute -top-40 -left-40 w-[900px] h-[900px] bg-red-600/15 rounded-full blur-[180px]"
          animate={{
            x: ["0%", "15%", "0%"],
            y: ["0%", "10%", "0%"],
          }}
          transition={{
            duration: 25,
            repeat: Infinity,
            ease: "easeInOut",
          }}
        />

        {/* Blob 2 */}
        <motion.div
          className="absolute bottom-0 right-0 w-[800px] h-[800px] bg-red-500/12 rounded-full blur-[200px]"
          animate={{
            x: ["0%", "-15%", "0%"],
            y: ["0%", "-10%", "0%"],
          }}
          transition={{
            duration: 30,
            repeat: Infinity,
            ease: "easeInOut",
          }}
        />

        {/* Oscurecedor suave */}
        <div className="absolute inset-0 bg-gradient-to-b from-black via-black/80 to-black" />
      </div>

      <Navbar />

      <SectionWrapper>
        <Hero />
      </SectionWrapper>

      <SectionWrapper>
        <About />
      </SectionWrapper>

      <SectionWrapper>
        <Projects />
      </SectionWrapper>

      <SectionWrapper>
        <Stack />
      </SectionWrapper>

      <SectionWrapper>
        <Contact />
      </SectionWrapper>

      <Footer />
    </motion.div>
  );
}

export default App;

// components/Contact.jsx

import { useState } from "react";
import { motion } from "framer-motion";
import { Github, Linkedin, Mail, Copy, Check } from "lucide-react";

export default function Contact() {
  const [copied, setCopied] = useState(false);
  const email = "esteban_690@hotmail.com";

  const handleCopy = () => {
    navigator.clipboard.writeText(email);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };
  return (
    <section
      id="contact"
      className="py-28 px-8 md:px-20 text-white"
    >
      <div className="max-w-4xl mx-auto text-left">
        {/* Title */}
        <motion.h2
          initial={{ opacity: 0, x: -40 }}
          whileInView={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="text-2xl md:text-3xl font-semibold mb-12 tracking-tight"
        >
          <span className="text-red-500">/</span> Contacto
        </motion.h2>

        {/* Description */}
        <motion.p
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="text-sm text-gray-400 leading-relaxed mb-12 max-w-xl"
        >
          Actualmente disponible para oportunidades como Full Stack Developer.
          Interesado en proyectos desafiantes donde pueda aportar arquitectura
          limpia, integraci├│n frontend-backend y soluciones escalables.
        </motion.p>

        {/* Social Links */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.2 }}
          viewport={{ once: true }}
          className="flex gap-10"
        >
          <a
            href="https://github.com/EstebanRioss"
            className="group flex items-center gap-3 text-gray-400 hover:text-red-500 transition-all duration-300"
          >
            <Github className="w-5 h-5 group-hover:scale-110 transition" />
            <span className="text-sm tracking-wide">GitHub</span>
          </a>

          <a
            href="https://www.linkedin.com/in/esteban-rios-b6056a309/"
            className="group flex items-center gap-3 text-gray-400 hover:text-red-500 transition-all duration-300"
          >
            <Linkedin className="w-5 h-5 group-hover:scale-110 transition" />
            <span className="text-sm tracking-wide">LinkedIn</span>
          </a>

          <div className="flex items-center gap-2">
            <a
              href={`mailto:${email}`}
              className="group flex items-center gap-3 text-gray-400 hover:text-red-500 transition-all duration-300"
            >
              <Mail className="w-5 h-5 group-hover:scale-110 transition" />
              <span className="text-sm tracking-wide">Email</span>
            </a>
            <button
              onClick={handleCopy}
              className="p-1.5 ml-1 text-gray-500 hover:text-white hover:bg-white/10 rounded-md transition-colors"
              title="Copiar email"
            >
              {copied ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
            </button>
          </div>
        </motion.div>
      </div>
    </section>
  );
}

// components/Navbar.jsx

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X } from "lucide-react";
import { useScroll, useSpring } from "framer-motion";

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const { scrollYProgress } = useScroll();

  const scaleX = useSpring(scrollYProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001,
  });

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const navLinks = [
    { name: "Sobre m├¡", href: "#about" },
    { name: "Proyectos", href: "#projects" },
    { name: "Stack", href: "#stack" },
    { name: "Contacto", href: "#contact" },
  ];

  return (
    <motion.nav
      initial={{ y: -80, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.6 }}
      className={`fixed top-0 w-full z-50 transition-all duration-500 ${
        scrolled
          ? "bg-black/90 backdrop-blur-xl border-b border-red-600/30"
          : "bg-transparent"
      }`}
    >
      <div className="max-w-6xl mx-auto px-8 py-4 flex justify-between items-center">
        {/* LOGO */}
        <motion.div
          initial="hidden"
          animate="visible"
          whileHover={{ scale: 1.05 }}
          className="text-xl font-semibold tracking-tight cursor-pointer select-none flex"
        >
          <motion.span
            variants={{
              hidden: { opacity: 0, x: -20 },
              visible: { opacity: 1, x: 0 },
            }}
            transition={{ duration: 0.6 }}
            className="text-white"
          >
            Esteban
          </motion.span>

          <motion.span
            variants={{
              hidden: { opacity: 0, x: 20 },
              visible: { opacity: 1, x: 0 },
            }}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="text-red-600"
          >
            .dev
          </motion.span>
        </motion.div>

        {/* DESKTOP MENU */}
        <div className="hidden md:flex items-center gap-10">
          {navLinks.map((link, index) => (
            <motion.a
              key={link.name}
              href={link.href}
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3 + index * 0.1 }}
              whileHover={{ y: -2 }}
              className="relative text-sm tracking-wide text-gray-400 hover:text-red-500 transition-colors duration-300 group"
            >
              {link.name}
              <span className="absolute left-0 -bottom-1 h-[1px] w-0 bg-red-600 transition-all duration-300 group-hover:w-full" />
            </motion.a>
          ))}
          
          <motion.a
            href="/CV_Esteban_Rios.pdf"
            download
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.7 }}
            className="px-5 py-2 text-sm font-medium text-white bg-red-600 rounded-full hover:bg-red-700 transition-colors shadow-[0_0_15px_rgba(220,38,38,0.4)] hover:shadow-[0_0_25px_rgba(220,38,38,0.6)]"
          >
            Descargar CV
          </motion.a>
        </div>

        {/* MOBILE BUTTON */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="md:hidden text-red-500"
        >
          {isOpen ? <X size={26} /> : <Menu size={26} />}
        </button>
      </div>

      {/* MOBILE MENU */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.3 }}
            className="md:hidden bg-black border-t border-red-600/30"
          >
            <div className="flex flex-col items-center py-8 gap-8">
              {navLinks.map((link) => (
                <a
                  key={link.name}
                  href={link.href}
                  onClick={() => setIsOpen(false)}
                  className="text-sm tracking-wide text-gray-300 hover:text-red-500 transition duration-300"
                >
                  {link.name}
                </a>
              ))}
              <a
                href="/CV_Esteban_Rios.pdf"
                download
                className="px-6 py-2 block text-center text-sm font-medium text-white bg-red-600 rounded-full hover:bg-red-700 transition-colors shadow-[0_0_15px_rgba(220,38,38,0.4)]"
              >
                Descargar CV
              </a>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
      <motion.div
        style={{ scaleX }}
        className="absolute bottom-0 left-0 right-0 h-[2px] bg-red-600 origin-left "
      />
    </motion.nav>
  );
}

// components/Stack.jsx

import { motion } from "framer-motion";

function StackBlock({ title, items }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
      viewport={{ once: true }}
      className="border border-red-600/20 rounded-xl p-6 hover:border-red-600/40 transition-all duration-300"
    >
      <h3 className="text-sm uppercase tracking-widest text-gray-500 mb-4">
        {title}
      </h3>

      <div className="space-y-2">
        {items.map((item, index) => (
          <p
            key={index}
            className="text-sm text-gray-300 hover:text-red-400 transition"
          >
            {item}
          </p>
        ))}
      </div>
    </motion.div>
  );
}

export default function Stack() {
  return (
    <section
      id="stack"
      className="py-28 px-8 md:px-20 text-white"
